// Master Router POSTs the events row body. Pull payload, verify shape.
const raw = $input.first().json;
const body = raw.body || raw;

const payload = (body.payload && typeof body.payload === 'object')
  ? body.payload
  : (typeof body.payload === 'string' ? JSON.parse(body.payload) : {});

const event_id        = body.id || raw.id;
const trace_id        = body.trace_id || raw.trace_id;
const gmail_message_id = payload.gmail_message_id;
const attachment_id   = payload.attachment_id;
const filename        = payload.filename;
const mime_type       = String(payload.mime_type || 'application/octet-stream').toLowerCase();
const email_id        = payload.email_id ?? null;  // B3_VALIDATE_v1
const account         = payload.account || 'personal1';

if (!event_id)         throw new Error('missing event id');
if (!trace_id)         throw new Error('missing trace_id');
if (!gmail_message_id) throw new Error('payload missing gmail_message_id');
if (!attachment_id)    throw new Error('payload missing attachment_id');
if (!filename)         throw new Error('payload missing filename');
// email_id is optional in B3 design — looked up from emails table
// at INSERT time via gmail_message_id, with NULL fallback if the
// email pipeline hasn't INSERTed the emails row yet.

// Choose pdfplumber endpoint by MIME type. Other types → unknown handling.
let pdfplumber_endpoint = null;
if (mime_type === 'application/pdf') {
  pdfplumber_endpoint = '/extract-pdf';
} else if (mime_type.includes('spreadsheet') || filename.toLowerCase().endsWith('.xlsx')) {
  pdfplumber_endpoint = '/parse-xlsx';
} else if (mime_type.includes('csv') || filename.toLowerCase().endsWith('.csv')) {
  pdfplumber_endpoint = '/parse-csv';
}

return [{
  json: {
    event_id, trace_id, email_id, gmail_message_id, attachment_id,
    filename, mime_type, account, pdfplumber_endpoint,
    parent_event_id: event_id
  }
}];

// Gmail returns attachment as base64url-encoded `data`. Convert to a binary
// buffer and attach so the next HTTP node can multipart-POST it to pdfplumber.
const attachment = $input.first().json;
if (!attachment.data) throw new Error('Gmail attachment fetch returned no data');

// base64url → base64 → buffer
const b64 = attachment.data.replace(/-/g, '+').replace(/_/g, '/');
const pad = b64.length % 4;
const b64padded = pad ? b64 + '='.repeat(4 - pad) : b64;
const buffer = Buffer.from(b64padded, 'base64');

const v = $('Validate Event').first().json;
if (buffer.length > 25 * 1024 * 1024) {
  throw new Error(`attachment ${v.filename} is ${buffer.length} bytes (>25MB cap)`);
}

return [{
  json: { ...v, attachment_size: buffer.length },
  binary: {
    file: {
      data:     buffer.toString('base64'),
      fileName: v.filename,
      mimeType: v.mime_type
    }
  }
}];

// pdfplumber returns either {text, content_hash} or {data: [...rows...]}.
// Normalise to a single 'extracted_text' string for the classifier.
const pdfp = $input.first().json;
let text = '';
if (pdfp.text) {
  text = pdfp.text;
} else if (Array.isArray(pdfp.data)) {
  // For xlsx/csv: serialize the first 200 rows as TSV-ish
  text = pdfp.data.slice(0, 200).map(r => Object.values(r).join('\t')).join('\n');
}

// SPEC §2.4 sanitiser — strip control chars, cap at 8000 chars
text = String(text).replace(/[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]/g, '').slice(0, 8000);

const v = $('Validate Event').first().json;
const crypto = require('crypto');
const content_hash = crypto.createHash('sha256').update(text).digest('hex');

return [{
  json: {
    ...v,
    extracted_text: text,
    content_hash,
    classifier_prompt: text
  }
}];

// Parse Haiku response → OutcomeObject (SPEC §6.2 v5.3 mandatory).
const item = $input.first().json;
const v = $('Sanitise + Build Prompt').first().json;

let ai;
try {
  const text = item.content?.[0]?.text || '{}';
  ai = JSON.parse(text);
} catch (e) {
  ai = { document_type: 'unknown', confidence_score: 0,
         summary: 'parse error', requires_human: true };
}

const validTypes = ['bank_statement','supplier_invoice','property_agent_report',
                    'epos_report','accommodation_report','payroll_report',
                    'analytics_report','unknown'];
const document_type = validTypes.includes(ai.document_type) ? ai.document_type : 'unknown';
const confidence    = Math.min(1, Math.max(0, Number(ai.confidence_score) || 0));
const summary       = String(ai.summary || '').slice(0, 200);

const min_conf = 0.70; // SPEC §6.2 P9: type=unknown if confidence < 0.70
const status = confidence >= min_conf
  ? 'success'
  : confidence >= min_conf * 0.85
    ? 'escalate'
    : 'fail';

const outcome = {
  status,
  confidence,
  reasoning:    String(ai.summary || ai.reasoning || '').slice(0, 1000),
  data:         { document_type, summary, requires_human: !!ai.requires_human },
  requires_human: status === 'fail' || !!ai.requires_human || confidence < min_conf,
  worker:       'report_parser',
  tier_used:    'haiku'
};

const crypto = require('crypto');
const signing_key = $('Vault: Signing Key').first().json.data.data.payload_hmac_key;
const canonical = JSON.stringify(outcome, Object.keys(outcome).sort());
const signature = crypto.createHmac('sha256', signing_key).update(canonical).digest('hex');

return [{
  json: {
    ...v,
    document_type,
    confidence,
    summary,
    requires_human: outcome.requires_human,
    outcome,
    outcome_json: JSON.stringify(outcome),
    outcome_signature: signature,
    ai_raw: JSON.stringify(item.content || item)
  }
}];
